// - Switching to different algorithms based on data characteristics

pub fn adaptive_sort<T: Ord + Clone>(arr: &mut [T]) {
    let n = arr.len();
    if n < 2 { return; }
    let (mut asc, mut desc) = (true, true);
    for i in 1..n {
        if arr[i-1] > arr[i] { asc = false; if !desc { break; } }
        else if arr[i-1] < arr[i] { desc = false; if !asc { break; } }
    }
    if asc { return; }
    if desc { return arr.reverse(); }

    quicksort(arr);
    for i in 1..n {
        let mut j = i;
        while j > 0 && arr[j - 1] > arr[j] {
            arr.swap(j, j - 1);
            j -= 1;
        }
    }
}

fn quicksort<T: Ord + Clone>(mut arr: &mut [T]) {
    while arr.len() > 20 {
        let (mid, last) = (arr.len() / 2, arr.len() - 1);
        if arr[mid] < arr[0] { arr.swap(0, mid); }
        if arr[last] < arr[0] { arr.swap(0, last); }
        if arr[last] < arr[mid] { arr.swap(mid, last); }
        let pivot = arr[mid].clone();
        let (mut lt, mut i, mut gt) = (0, 0, last);
        while i <= gt {
            match arr[i].cmp(&pivot) {
                Ordering::Less => { arr.swap(lt, i); lt += 1; i += 1; }
                Ordering::Greater => { arr.swap(i, gt); gt -= 1; }
                Ordering::Equal => { i += 1; }
            }
        }
        if lt < arr.len() - i {
            quicksort(&mut arr[..lt]);
            arr = &mut arr[i..];
        } else {
            quicksort(&mut arr[i..]);
            arr = &mut arr[..lt];
        }
    }
}
